function calculate({
  socialFollowers,
  avgEngagementRate,
  contentFrequency,
  websiteTraffic,
  mediaMentions,
  audienceDiversityScore,
  conversionRate,
  authorityScore
}) {
  // Default and sanitize inputs
  const safeFollowers = Math.max(0, socialFollowers || 0);
  const safeEngagementRate = Math.max(0, Math.min(100, avgEngagementRate || 0)); // Cap at 100%
  const safeContentFrequency = Math.max(0, contentFrequency || 0);
  const safeWebsiteTraffic = Math.max(0, websiteTraffic || 0);
  const safeMediaMentions = Math.max(0, mediaMentions || 0);
  const safeAudienceDiversity = Math.max(1, Math.min(5, audienceDiversityScore || 1)); // Cap between 1 and 5
  const safeConversionRate = Math.max(0, Math.min(100, conversionRate || 0)); // Cap at 100%
  const safeAuthorityScore = Math.max(1, Math.min(10, authorityScore || 1)); // Cap between 1 and 10

  // Define maximum thresholds for normalization to dampen extreme values
  const MAX_FOLLOWERS = 5_000_000; // 5 million followers
  const MAX_WEBSITE_TRAFFIC = 1_000_000; // 1 million visitors
  const MAX_MEDIA_MENTIONS = 50; // 50 significant mentions quarterly
  const MAX_CONTENT_FREQUENCY = 25; // 25 pieces per week
  const MAX_EFFECTIVE_ENGAGEMENT_RATE = 10; // 10% is considered exceptionally high for most brands
  const MAX_EFFECTIVE_CONVERSION_RATE = 5; // 5% is very strong for most call-to-actions

  // --- Step 1: Normalize all input metrics to a 0-1 scale ---
  // Logarithmic scaling for large numbers (followers, website traffic)
  const normFollowers = Math.min(Math.log10(safeFollowers + 1) / Math.log10(MAX_FOLLOWERS + 1), 1);
  const normWebsiteTraffic = Math.min(Math.log10(safeWebsiteTraffic + 1) / Math.log10(MAX_WEBSITE_TRAFFIC + 1), 1);
  // Linear scaling for others, with caps for diminishing returns/realistic max
  const normMediaMentions = Math.min(safeMediaMentions / MAX_MEDIA_MENTIONS, 1);
  const normContentFrequency = Math.min(safeContentFrequency / MAX_CONTENT_FREQUENCY, 1);
  const normEngagementRate = Math.min(safeEngagementRate / MAX_EFFECTIVE_ENGAGEMENT_RATE, 1);
  const normConversionRate = Math.min(safeConversionRate / MAX_EFFECTIVE_CONVERSION_RATE, 1);
  // Direct scaling for scores
  const normAudienceDiversity = safeAudienceDiversity / 5;
  const normAuthority = safeAuthorityScore / 10;

  // --- Step 2: Calculate three weighted sub-scores (0-1 scale) ---
  // A. Digital Reach Base (potential audience size)
  const reachBase = (
    normFollowers * 0.45 +
    normWebsiteTraffic * 0.35 +
    normMediaMentions * 0.20
  );

  // B. Engagement Quality Base (audience interaction & consistency)
  const engagementBase = (
    normEngagementRate * 0.50 +
    normContentFrequency * 0.25 +
    normAudienceDiversity * 0.25
  );

  // C. Impact & Authority Base (influence depth and perceived expertise)
  const impactBase = (
    normAuthority * 0.60 +
    normConversionRate * 0.40
  );

  // --- Step 3: Combine sub-scores to calculate the Personal Brand Influence Score (0-1000) ---
  const influenceScore = Math.round(
    (reachBase * 0.40 + engagementBase * 0.35 + impactBase * 0.25) * 1000
  );

  // --- Step 4: Calculate the Digital Reach Index (0-1000) ---
  // Emphasizes raw reach metrics more directly than the influence score
  const reachIndex = Math.round(
    (normFollowers * 0.55 + normWebsiteTraffic * 0.30 + normMediaMentions * 0.15) * 1000
  );

  // --- Step 5: Determine Engagement Quality Rating ---
  let engagementQuality;
  if (engagementBase < 0.25) {
    engagementQuality = "Low";
  } else if (engagementBase < 0.50) {
    engagementQuality = "Moderate";
  } else if (engagementBase < 0.75) {
    engagementQuality = "High";
  } else {
    engagementQuality = "Exceptional";
  }

  return {
    influenceScore,
    reachIndex,
    engagementQuality
  };
}
